// biome-ignore lint/performance/noBarrelFile: runtime icon public package surface
export { CplusplusIcon, CplusplusIcon as CppIcon } from "./cplusplus";
export { DotNetIcon } from "./dotnet";
export { GoIcon } from "./go";
export { JavaIcon } from "./java";
export { NodeJsIcon } from "./nodejs";
export { PhpIcon } from "./php";
export { PythonIcon } from "./python";
export { RubyIcon } from "./ruby";
export { RustIcon } from "./rust";
export type { RuntimeIconProps } from "./types";

import type {
  CanvasNodeConnectionEvent,
  CanvasNodeConnectionSide,
  CanvasNodeInteractionState,
  CanvasNodeStatus,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export type EnvironmentRuntimeKey =
  | "cpp"
  | "dotnet"
  | "go"
  | "java"
  | "nodejs"
  | "php"
  | "python"
  | "ruby"
  | "rust"
  | (string & {});

export type EnvironmentNodeMetricKey = "cpu" | "memory" | "storage";

export type EnvironmentNodeMetricValue = number | string;

export interface EnvironmentNodeStates {
  displayRuntime: string;
  formattedVersion?: string;
  metrics?: Partial<
    Record<EnvironmentNodeMetricKey, EnvironmentNodeMetricValue>
  >;
  name: string;
  runtimeKey?: EnvironmentRuntimeKey;
  status?: CanvasNodeStatus;
}

export type EnvironmentNodeQuickActionKey =
  | "ide"
  | "logs"
  | "metrics"
  | "terminal";

export type EnvironmentNodeLifecycleActionKey =
  | "delete"
  | "restart"
  | "start"
  | "stop";

export interface EnvironmentNodeAction {
  disabled?: boolean;
  loading?: boolean;
  onClick?: () => Promise<void> | void;
}

export type EnvironmentNodeQuickActions = Partial<
  Record<EnvironmentNodeQuickActionKey, EnvironmentNodeAction>
>;

export type EnvironmentNodeLifecycleActions = Partial<
  Record<EnvironmentNodeLifecycleActionKey, EnvironmentNodeAction>
>;

export type EnvironmentNodeCopyLaunchCommandHandler = (
  launchCommand: string
) => Promise<void> | void;

export type EnvironmentNodeStartConnectionHandler = (
  side: CanvasNodeConnectionSide,
  event: CanvasNodeConnectionEvent
) => void;

export interface EnvironmentNodeActions {
  copyLaunchCommand: EnvironmentNodeCopyLaunchCommandHandler;
  lifecycleActions?: EnvironmentNodeLifecycleActions;
  quickActions?: EnvironmentNodeQuickActions;
}

export interface EnvironmentNodeMeta {
  copiedFeedbackMs?: number;
}

export interface EnvironmentNodeState {
  copiedLaunchCommand?: boolean;
  launchCommand?: string;
  states: EnvironmentNodeStates;
}

export interface EnvironmentNodeContextValue {
  actions: EnvironmentNodeActions;
  meta: EnvironmentNodeMeta;
  state: EnvironmentNodeState;
}

export interface EnvironmentNodeProviderProps {
  children?: ReactNode;
  value: EnvironmentNodeContextValue;
}

export interface EnvironmentNodeRootProps {
  children?: ReactNode;
  copiedFeedbackMs?: number;
  copiedLaunchCommand?: boolean;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  launchCommand?: string;
  lifecycleActions?: EnvironmentNodeLifecycleActions;
  onCopyLaunchCommand?: EnvironmentNodeCopyLaunchCommandHandler;
  onExpandedChange?: (expanded: boolean) => void;
  onStartConnection?: EnvironmentNodeStartConnectionHandler;
  quickActions?: EnvironmentNodeQuickActions;
  states: EnvironmentNodeStates;
}

"use client";

import { createContext, use } from "react";

import type { EnvironmentNodeContextValue } from "./environment-node.types";

export const EnvironmentNodeContext =
  createContext<EnvironmentNodeContextValue | null>(null);

export function useEnvironmentNode(): EnvironmentNodeContextValue {
  const value = use(EnvironmentNodeContext);

  if (!value) {
    throw new Error(
      "EnvironmentNode: compound components must be used within EnvironmentNode.Root"
    );
  }

  return value;
}

"use client";

import { EnvironmentNodeContext } from "./environment-node.context";
import type { EnvironmentNodeProviderProps } from "./environment-node.types";

export function EnvironmentNodeProvider({
  children,
  value,
}: EnvironmentNodeProviderProps) {
  return (
    <EnvironmentNodeContext value={value}>{children}</EnvironmentNodeContext>
  );
}

"use client";

import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { EnvironmentNodeProvider } from "./environment-node.provider";
import type {
  EnvironmentNodeContextValue,
  EnvironmentNodeRootProps,
} from "./environment-node.types";

const DEFAULT_COPIED_FEEDBACK_MS = 1200;

async function copyTextToClipboard(value: string) {
  if (typeof navigator === "undefined" || !navigator.clipboard) {
    return;
  }

  await navigator.clipboard.writeText(value);
}

export function canCopyEnvironmentLaunchCommand(
  launchCommand: string | undefined
) {
  return Boolean(launchCommand?.trim());
}

export function EnvironmentNodeRoot({
  children,
  copiedFeedbackMs = DEFAULT_COPIED_FEEDBACK_MS,
  copiedLaunchCommand,
  defaultExpanded,
  expanded,
  interaction,
  launchCommand,
  lifecycleActions,
  onCopyLaunchCommand,
  onExpandedChange,
  onStartConnection,
  quickActions,
  states,
}: EnvironmentNodeRootProps) {
  const [internalCopiedLaunchCommand, setInternalCopiedLaunchCommand] =
    useState(false);
  const resetTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const copiedLaunchCommandControlled = copiedLaunchCommand !== undefined;

  useEffect(
    () => () => {
      if (resetTimerRef.current) {
        clearTimeout(resetTimerRef.current);
      }
    },
    []
  );

  const showCopiedFeedback = useCallback(() => {
    if (copiedLaunchCommandControlled) {
      return;
    }

    setInternalCopiedLaunchCommand(true);

    if (resetTimerRef.current) {
      clearTimeout(resetTimerRef.current);
    }

    resetTimerRef.current = setTimeout(() => {
      setInternalCopiedLaunchCommand(false);
      resetTimerRef.current = null;
    }, copiedFeedbackMs);
  }, [copiedFeedbackMs, copiedLaunchCommandControlled]);

  const copyLaunchCommand = useCallback(
    async (command: string) => {
      if (!canCopyEnvironmentLaunchCommand(command)) {
        return;
      }

      showCopiedFeedback();

      if (onCopyLaunchCommand) {
        await onCopyLaunchCommand(command);
      } else {
        await copyTextToClipboard(command);
      }
    },
    [onCopyLaunchCommand, showCopiedFeedback]
  );

  const value = useMemo(
    (): EnvironmentNodeContextValue => ({
      actions: {
        copyLaunchCommand,
        lifecycleActions,
        quickActions,
      },
      meta: {
        copiedFeedbackMs,
      },
      state: {
        copiedLaunchCommand: copiedLaunchCommandControlled
          ? copiedLaunchCommand
          : internalCopiedLaunchCommand,
        launchCommand,
        states,
      },
    }),
    [
      copiedFeedbackMs,
      copiedLaunchCommand,
      copiedLaunchCommandControlled,
      copyLaunchCommand,
      internalCopiedLaunchCommand,
      launchCommand,
      lifecycleActions,
      quickActions,
      states,
    ]
  );

  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
      onStartConnection={onStartConnection}
    >
      <EnvironmentNodeProvider value={value}>
        {children}
      </EnvironmentNodeProvider>
    </CanvasNodeRoot>
  );
}

import { Box } from "lucide-react";
import type { ComponentType } from "react";
import {
  CppIcon,
  DotNetIcon,
  GoIcon,
  JavaIcon,
  NodeJsIcon,
  PhpIcon,
  PythonIcon,
  RubyIcon,
  type RuntimeIconProps,
  RustIcon,
} from "../../assets/runtime-icons";

import type { EnvironmentRuntimeKey } from "./environment-node.types";

export type EnvironmentRuntimeIcon = ComponentType<RuntimeIconProps>;

export type EnvironmentRuntimeTone =
  | "blue"
  | "cyan"
  | "green"
  | "neutral"
  | "orange"
  | "purple"
  | "red"
  | "yellow";

export function EnvironmentFallbackIcon({
  size = 24,
  ...props
}: RuntimeIconProps) {
  return <Box size={size} {...props} />;
}

export const NodeJsRuntimeIcon = NodeJsIcon;
export const GoRuntimeIcon = GoIcon;
export const PythonRuntimeIcon = PythonIcon;
export const JavaRuntimeIcon = JavaIcon;
export const RustRuntimeIcon = RustIcon;
export const PhpRuntimeIcon = PhpIcon;
export const RubyRuntimeIcon = RubyIcon;
export const CppRuntimeIcon = CppIcon;
export const DotNetRuntimeIcon = DotNetIcon;

const ENVIRONMENT_RUNTIME_ICONS = {
  cpp: CppRuntimeIcon,
  dotnet: DotNetRuntimeIcon,
  go: GoRuntimeIcon,
  java: JavaRuntimeIcon,
  nodejs: NodeJsRuntimeIcon,
  php: PhpRuntimeIcon,
  python: PythonRuntimeIcon,
  ruby: RubyRuntimeIcon,
  rust: RustRuntimeIcon,
} as const satisfies Record<string, EnvironmentRuntimeIcon>;

const ENVIRONMENT_RUNTIME_TONES = {
  cpp: "blue",
  dotnet: "purple",
  go: "cyan",
  java: "orange",
  nodejs: "green",
  php: "purple",
  python: "yellow",
  ruby: "red",
  rust: "orange",
} as const satisfies Record<string, EnvironmentRuntimeTone>;

export function normalizeEnvironmentRuntimeKey(
  runtimeKey: EnvironmentRuntimeKey
) {
  return runtimeKey.trim().toLowerCase();
}

export function getEnvironmentRuntimeIcon(
  runtimeKey: EnvironmentRuntimeKey | undefined
) {
  if (!runtimeKey) {
    return EnvironmentFallbackIcon;
  }

  return (
    ENVIRONMENT_RUNTIME_ICONS[
      normalizeEnvironmentRuntimeKey(
        runtimeKey
      ) as keyof typeof ENVIRONMENT_RUNTIME_ICONS
    ] ?? EnvironmentFallbackIcon
  );
}

export function getEnvironmentRuntimeTone(
  runtimeKey: EnvironmentRuntimeKey | undefined
): EnvironmentRuntimeTone {
  if (!runtimeKey) {
    return "neutral";
  }

  return (
    ENVIRONMENT_RUNTIME_TONES[
      normalizeEnvironmentRuntimeKey(
        runtimeKey
      ) as keyof typeof ENVIRONMENT_RUNTIME_TONES
    ] ?? "neutral"
  );
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import {
  Activity,
  Check,
  Code2,
  Copy,
  Cpu,
  FileText,
  HardDrive,
  MemoryStick,
  Pause,
  Play,
  RotateCcw,
  SquareTerminal,
  Trash2,
} from "lucide-react";
import type { ComponentType, SVGProps, SyntheticEvent } from "react";

import { useEnvironmentNode } from "./environment-node.context";
import { canCopyEnvironmentLaunchCommand } from "./environment-node.root";
import type {
  EnvironmentNodeLifecycleActionKey,
  EnvironmentNodeMetricKey,
  EnvironmentNodeQuickActionKey,
} from "./environment-node.types";
import {
  type EnvironmentRuntimeTone,
  getEnvironmentRuntimeIcon,
  getEnvironmentRuntimeTone,
} from "./environment-runtime-icons";

const RF_CONTROL_CLASS = "nodrag nopan";

const METRIC_ITEMS = [
  { icon: Cpu, key: "cpu", label: "CPU" },
  { icon: MemoryStick, key: "memory", label: "Memory" },
  { icon: HardDrive, key: "storage", label: "Storage" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: EnvironmentNodeMetricKey;
  label: string;
}[];

const QUICK_ACTION_ITEMS = [
  { icon: SquareTerminal, key: "terminal", label: "Open terminal" },
  { icon: FileText, key: "logs", label: "Open logs" },
  { icon: Activity, key: "metrics", label: "Open metrics" },
  { icon: Code2, key: "ide", label: "Open IDE" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: EnvironmentNodeQuickActionKey;
  label: string;
}[];

interface LifecycleActionItem {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: EnvironmentNodeLifecycleActionKey;
  label: string;
  tone?: "destructive" | "info" | "muted" | "success";
}

const LIFECYCLE_ACTION_ITEMS: readonly LifecycleActionItem[] = [
  { icon: Play, key: "start", label: "Start", tone: "success" },
  { icon: Pause, key: "stop", label: "Stop", tone: "muted" },
  { icon: RotateCcw, key: "restart", label: "Restart", tone: "info" },
  { icon: Trash2, key: "delete", label: "Delete", tone: "destructive" },
] as const;

function stopNodeControlEvent(event: SyntheticEvent) {
  event.stopPropagation();
}

function formatEnvironmentSubtitle({
  displayRuntime,
  formattedVersion,
}: {
  displayRuntime: string;
  formattedVersion?: string;
}) {
  const runtime = displayRuntime.trim() || "Unknown runtime";

  return `Environment ${runtime}${formattedVersion ? ` ${formattedVersion}` : ""}`;
}

function formatEnvironmentMetricValue(value: number | string | undefined) {
  if (typeof value === "number") {
    return `${value}%`;
  }

  const trimmed = value?.trim();

  return trimmed || "--";
}

function getRuntimeToneClassName(tone: EnvironmentRuntimeTone) {
  switch (tone) {
    case "blue":
      return "text-blue-400";
    case "cyan":
      return "text-cyan-400";
    case "green":
      return "text-green-400";
    case "orange":
      return "text-orange-400";
    case "purple":
      return "text-purple-400";
    case "red":
      return "text-red-400";
    case "yellow":
      return "text-yellow-400";
    default:
      return "text-zinc-50";
  }
}

function renderLaunchCommandCopyIndicator({
  copied,
  copyable,
}: {
  copied: boolean;
  copyable: boolean;
}) {
  if (!copyable) {
    return null;
  }

  if (copied) {
    return <Check aria-hidden className="size-4 shrink-0" />;
  }

  return (
    <Copy
      aria-hidden
      className="environment-node-launch-command-copy-icon size-4 shrink-0 opacity-0 transition-opacity group-hover/launch-command:opacity-100"
    />
  );
}

export function EnvironmentNodeContent() {
  return (
    <CanvasNode.Card surfaceClassName="environment-node-surface">
      <CanvasNode.Header>
        <EnvironmentNodeHeaderContent />
      </CanvasNode.Header>
      <CanvasNode.Body>
        <EnvironmentNodeBodyContent />
      </CanvasNode.Body>
      <CanvasNode.Footer>
        <EnvironmentNodeFooterContent />
      </CanvasNode.Footer>
    </CanvasNode.Card>
  );
}

export function EnvironmentNodeHeaderContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: { states },
  } = useEnvironmentNode();
  const Icon = getEnvironmentRuntimeIcon(states.runtimeKey);
  const runtimeTone = getEnvironmentRuntimeTone(states.runtimeKey);
  const subtitle = formatEnvironmentSubtitle(states);

  return (
    <div className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span className="flex min-w-0 flex-1 items-center gap-1.5">
        <span
          className={cn(
            "flex size-9 shrink-0 items-center justify-center rounded-lg bg-white/5",
            getRuntimeToneClassName(runtimeTone)
          )}
        >
          <Icon aria-hidden className="size-4" strokeWidth={2} />
        </span>
        <span className="flex min-w-0 flex-1 flex-col gap-1.5">
          <span
            className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
            title={states.name}
          >
            {states.name}
          </span>
          <span
            className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4"
            title={subtitle}
          >
            {subtitle}
          </span>
        </span>
      </span>
      <EnvironmentNodeHeaderMenu />
    </div>
  );
}

export function EnvironmentNodeBodyContent({
  className,
}: {
  className?: string;
}) {
  return (
    <div className={cn("environment-node-body-content pt-2.5", className)}>
      <EnvironmentNodeLaunchCommand />
      <EnvironmentNodeActionBar />
    </div>
  );
}

export function EnvironmentNodeLaunchCommand({
  className,
}: {
  className?: string;
}) {
  const {
    actions,
    state: { copiedLaunchCommand = false, launchCommand },
  } = useEnvironmentNode();
  const copyable = canCopyEnvironmentLaunchCommand(launchCommand);
  const displayValue = copyable
    ? launchCommand
    : "No launch command configured";

  const copyLaunchCommand = () => {
    if (!(copyable && launchCommand)) {
      return;
    }

    Promise.resolve(actions.copyLaunchCommand(launchCommand)).catch(
      () => undefined
    );
  };

  return (
    <section
      className={cn(
        "group/launch-command environment-node-launch-command-row relative flex min-w-0 flex-col gap-2 rounded-lg bg-zinc-950/20 p-2.5 transition-colors",
        !copyable && "environment-node-launch-command-row-static",
        className
      )}
      data-copyable={copyable || undefined}
      data-slot="environment-node-launch-command-row"
    >
      {copyable ? (
        <button
          aria-label="Copy launch command"
          className={cn(
            RF_CONTROL_CLASS,
            "environment-node-launch-command-copy-hitarea absolute inset-0 z-0 cursor-pointer rounded-lg focus-visible:outline-none"
          )}
          data-slot="environment-node-launch-command-copy"
          onClick={(event) => {
            event.stopPropagation();
            copyLaunchCommand();
          }}
          onDoubleClick={stopNodeControlEvent}
          onKeyDown={stopNodeControlEvent}
          onPointerDown={stopNodeControlEvent}
          title={launchCommand}
          type="button"
        />
      ) : null}
      <div
        className={cn(
          "relative z-10 flex min-w-0 items-center justify-between gap-2",
          copyable ? "pointer-events-none" : "pointer-events-auto"
        )}
      >
        <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
          Launch command
        </span>
      </div>
      <div
        aria-hidden={copyable ? true : undefined}
        className={cn(
          "relative z-10 flex h-7 min-w-0 items-center justify-between gap-2 py-1.5 text-left font-normal text-xs leading-4",
          copyable
            ? "pointer-events-none text-zinc-50"
            : "text-muted-foreground"
        )}
        data-copied={copiedLaunchCommand ? "true" : undefined}
        data-slot="environment-node-launch-command-value"
        title={launchCommand ?? displayValue}
      >
        <span className="min-w-0 truncate">{displayValue}</span>
        {renderLaunchCommandCopyIndicator({
          copied: copiedLaunchCommand,
          copyable,
        })}
      </div>
    </section>
  );
}

export function EnvironmentNodeActionBar({
  className,
}: {
  className?: string;
}) {
  const {
    actions: { quickActions },
  } = useEnvironmentNode();

  return (
    <CanvasNode.ActionBar className={className}>
      {QUICK_ACTION_ITEMS.map((item) => {
        const action = quickActions?.[item.key];
        const Icon = item.icon;

        return (
          <CanvasNode.ActionButton
            action={action}
            aria-label={item.label}
            key={item.key}
            title={item.label}
          >
            <Icon aria-hidden className="size-4" />
          </CanvasNode.ActionButton>
        );
      })}
    </CanvasNode.ActionBar>
  );
}

export function EnvironmentNodeFooterContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: {
      states: { metrics, status },
    },
  } = useEnvironmentNode();

  return (
    <div
      className={cn(
        "environment-node-footer-content flex w-full min-w-0 items-center justify-between gap-2 text-xs leading-none",
        className
      )}
      data-slot="environment-node-footer-content"
    >
      <CanvasNode.FooterStatus status={status} />
      <CanvasNode.Metrics>
        {METRIC_ITEMS.map((item) => {
          const Icon = item.icon;

          return (
            <CanvasNode.Metric
              key={item.key}
              label={item.label}
              value={formatEnvironmentMetricValue(metrics?.[item.key])}
            >
              <Icon aria-hidden className="size-3.5 shrink-0" />
            </CanvasNode.Metric>
          );
        })}
      </CanvasNode.Metrics>
    </div>
  );
}

function EnvironmentNodeHeaderMenu() {
  const {
    actions: { lifecycleActions },
  } = useEnvironmentNode();

  return (
    <CanvasNode.ActionMenu aria-label="Open environment actions">
      {LIFECYCLE_ACTION_ITEMS.map((item) => {
        const action = lifecycleActions?.[item.key];
        const Icon = item.icon;

        return (
          <CanvasNode.ActionMenuItem
            action={action}
            actionKey={item.key}
            icon={<Icon aria-hidden className="size-4" />}
            key={item.key}
            tone={item.tone}
          >
            {item.label}
          </CanvasNode.ActionMenuItem>
        );
      })}
    </CanvasNode.ActionMenu>
  );
}

.environment-node-launch-command-row[data-copyable]:hover,
.environment-node-launch-command-row:has(
    .environment-node-launch-command-copy-hitarea:focus-visible
  ) {
  background: color-mix(in oklab, var(--color-white) 4.5%, transparent);
}

.environment-node-launch-command-row:has(
    .environment-node-launch-command-copy-hitarea:focus-visible
  )
  .environment-node-launch-command-copy-icon {
  opacity: 1;
}

.environment-node-launch-command-row {
  min-height: calc(var(--spacing) * 18);
}

"use client";

import "./environment-node.css";

import {
  EnvironmentNodeActionBar,
  EnvironmentNodeBodyContent,
  EnvironmentNodeContent,
  EnvironmentNodeFooterContent,
  EnvironmentNodeHeaderContent,
  EnvironmentNodeLaunchCommand,
} from "./environment-node.content";
import { EnvironmentNodeRoot } from "./environment-node.root";

// biome-ignore lint/performance/noBarrelFile: compound hook re-export for `import { useEnvironmentNode }`
export { useEnvironmentNode } from "./environment-node.context";
export {
  canCopyEnvironmentLaunchCommand,
  EnvironmentNodeRoot,
} from "./environment-node.root";
export type {
  EnvironmentNodeAction,
  EnvironmentNodeActions,
  EnvironmentNodeContextValue,
  EnvironmentNodeCopyLaunchCommandHandler,
  EnvironmentNodeLifecycleActionKey,
  EnvironmentNodeLifecycleActions,
  EnvironmentNodeMeta,
  EnvironmentNodeMetricKey,
  EnvironmentNodeMetricValue,
  EnvironmentNodeProviderProps,
  EnvironmentNodeQuickActionKey,
  EnvironmentNodeQuickActions,
  EnvironmentNodeRootProps,
  EnvironmentNodeStartConnectionHandler,
  EnvironmentNodeState,
  EnvironmentNodeStates,
  EnvironmentRuntimeKey,
} from "./environment-node.types";
export {
  CppRuntimeIcon,
  DotNetRuntimeIcon,
  EnvironmentFallbackIcon,
  GoRuntimeIcon,
  getEnvironmentRuntimeIcon,
  getEnvironmentRuntimeTone,
  JavaRuntimeIcon,
  NodeJsRuntimeIcon,
  PhpRuntimeIcon,
  PythonRuntimeIcon,
  RubyRuntimeIcon,
  RustRuntimeIcon,
} from "./environment-runtime-icons";

export const EnvironmentNode = {
  ActionBar: EnvironmentNodeActionBar,
  BodyContent: EnvironmentNodeBodyContent,
  Content: EnvironmentNodeContent,
  FooterContent: EnvironmentNodeFooterContent,
  HeaderContent: EnvironmentNodeHeaderContent,
  LaunchCommand: EnvironmentNodeLaunchCommand,
  Root: EnvironmentNodeRoot,
} as const;

const dn = (component: object, name: string) => {
  (component as { displayName?: string }).displayName = name;
};

dn(EnvironmentNodeRoot, "EnvironmentNode.Root");
dn(EnvironmentNodeContent, "EnvironmentNode.Content");
dn(EnvironmentNodeHeaderContent, "EnvironmentNode.HeaderContent");
dn(EnvironmentNodeBodyContent, "EnvironmentNode.BodyContent");
dn(EnvironmentNodeLaunchCommand, "EnvironmentNode.LaunchCommand");
dn(EnvironmentNodeActionBar, "EnvironmentNode.ActionBar");
dn(EnvironmentNodeFooterContent, "EnvironmentNode.FooterContent");
